import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.onyx.app/developers/overview";
const PLACEHOLDER_VALUE = "onyx_pat_CoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Onyx API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:onyx",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const onyxFirewall = {",
    '  name: "onyx",',
    '  description: "Onyx",',
    "  placeholders: {",
    `    ONYX_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://cloud.onyx.app",',
    "      auth: {",
    "        headers: {",
    '          "Authorization": "Bearer ${{ secrets.ONYX_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Onyx firewall config...");
  const ts = generateTypeScript();
  writeOutput("onyx", ts, import.meta.dirname);
}
